  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→import { getIntentById, updateIntentStatus } from "../intent/intent-queries";
 13→import type { IntentStatus } from "../intent/types";
 14→import { log } from "../telemetry/logger";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types — exported for tests
 18→// ---------------------------------------------------------------------------
 19→
 20→export type SessionDeps = {
 21→  surreal: Surreal;
 22→  shellExec: ShellExec;
 23→  brainBaseUrl: string;
 24→  spawnAgent?: SpawnAgentFn;
 25→};
 26→
 27→export type SessionErrorCode =
 28→  | "TASK_NOT_FOUND"
 29→  | "TASK_NOT_ASSIGNABLE"
 30→  | "AGENT_ALREADY_ACTIVE"
 31→  | "WORKSPACE_MISMATCH"
 32→  | "MISSING_TASK_ID"
 33→  | "WORKTREE_ERROR"
 34→  | "SESSION_NOT_FOUND"
 35→  | "SESSION_ERROR"
 36→  | "INTENT_NOT_AUTHORIZED";
 37→
 38→export type SessionError = {
 39→  code: SessionErrorCode;
 40→  message: string;
 41→  httpStatus: number;
 42→};
 43→
 44→export type SessionResult<T> =
 45→  | { ok: true; value: T }
 46→  | { ok: false; error: SessionError };
 47→
 48→export type OrchestratorSessionResult = SessionResult<{
 49→  agentSessionId: string;
 50→  streamId: string;
 51→  worktreeBranch: string;
 52→}>;
 53→
 54→export type SessionStatusResult = SessionResult<{
 55→  orchestratorStatus: OrchestratorStatus;
 56→  worktreeBranch?: string;
 57→  worktreePath?: string;
 58→  lastEventAt?: string;
 59→  startedAt?: string;
 60→  error?: string;
 61→}>;
 62→
 63→export type AbortSessionResult = SessionResult<{
 64→  aborted: boolean;
 65→  sessionId: string;
 66→}>;
 67→
 68→export type AcceptSessionResult = SessionResult<{
 69→  accepted: boolean;
 70→  sessionId: string;
 71→}>;
 72→
 73→export type ReviewResult = SessionResult<{
 74→  taskTitle: string;
 75→  diff: import("./worktree-manager").DiffResult;
 76→  session: {
