527→async function transitionIntentToExecuting(
528→  surreal: Surreal,
529→  intentId: string,
530→  sessionRecord: RecordId<"agent_session", string>,
531→): Promise<void> {
532→  await updateIntentStatus(surreal, intentId, "executing");
533→
534→  const intentRecord = new RecordId("intent", intentId);
535→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
536→  await surreal.query(
537→    "RELATE $intent->gates->$sess SET created_at = time::now();",
538→    { intent: intentRecord, sess: sessionRecord },
539→  );
540→
541→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
542→    intentId,
543→    sessionId: sessionRecord.id as string,
544→  });
545→}
