663→
664→type AcceptSessionInput = {
665→  surreal: Surreal;
666→  sessionId: string;
667→  summary: string;
668→  endAgentSession: (input: {
669→    surreal: Surreal;
670→    workspaceRecord: RecordId<"workspace", string>;
671→    sessionId: string;
672→    summary: string;
673→  }) => Promise<{ session_id: string; ended: boolean }>;
674→};
675→
676→export async function acceptOrchestratorSession(
677→  input: AcceptSessionInput,
678→): Promise<AcceptSessionResult> {
679→  const lookup = await lookupSession(input.surreal, input.sessionId);
680→  if (!lookup.ok) {
681→    return { ok: false, error: lookup.error };
682→  }
683→  const { session, record: sessionRecord, status } = lookup;
684→
685→  if (!ACCEPTABLE_STATUSES.has(status)) {
686→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
687→  }
688→
689→  const workspaceRecord = requireWorkspace(session, input.sessionId);
690→
691→  // 1. Update orchestrator_status to completed
692→  await input.surreal.update(sessionRecord).merge({
693→    orchestrator_status: "completed" as OrchestratorStatus,
694→  });
695→
696→  // 2. Clean up handle registry
697→  handleRegistry.delete(input.sessionId);
698→
699→  // 4. End the agent session
700→  await input.endAgentSession({
701→    surreal: input.surreal,
702→    workspaceRecord,
703→    sessionId: input.sessionId,
704→    summary: input.summary,
705→  });
706→
707→  return {
708→    ok: true,
709→    value: {
710→      accepted: true,
711→      sessionId: input.sessionId,
712→    },
713→  };
714→}
