847→// ---------------------------------------------------------------------------
848→// sendSessionPrompt
849→// ---------------------------------------------------------------------------
850→
851→type SendPromptInput = {
852→  surreal: Surreal;
853→  sessionId: string;
854→  text: string;
855→};
856→
857→export async function sendSessionPrompt(
858→  input: SendPromptInput,
859→): Promise<PromptSessionResult> {
860→  const lookup = await lookupSession(input.surreal, input.sessionId);
861→  if (!lookup.ok) {
862→    return { ok: false, error: lookup.error };
863→  }
864→  const { status } = lookup;
865→
866→  if (!PROMPTABLE_STATUSES.has(status)) {
867→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
868→  }
869→
870→  // The Claude Agent SDK uses a single query() call per conversation.
871→  // Follow-up prompts are not supported in this model.
872→  return {
873→    ok: false,
874→    error: {
875→      code: "SESSION_ERROR",
876→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
877→      httpStatus: 409,
878→    },
879→  };
880→}
