 56→export function createBrainServer(deps: ServerDependencies): ReturnType<typeof Bun.serve> {
 57→  const config = deps.config;
 58→
 59→  // Shell execution — shared by workspace and orchestrator routes
 60→  const shellExec: ShellExec = async (command, args, cwd) => {
 61→    const proc = Bun.spawn([command, ...args], { cwd, stdout: "pipe", stderr: "pipe" });
 62→    const [stdout, stderr] = await Promise.all([
 63→      new Response(proc.stdout).text(),
 64→      new Response(proc.stderr).text(),
 65→    ]);
 66→    const exitCode = await proc.exited;
 67→    return { exitCode, stdout, stderr };
 68→  };
 69→
 70→  const workspaceHandlers = createWorkspaceRouteHandlers(deps, shellExec);
 71→  const chatHandlers = createChatIngressHandlers(deps);
 72→  const entitySearchHandler = createEntitySearchHandler(deps);
 73→  const graphHandler = createGraphRouteHandler(deps);
 74→  const entityDetailHandler = createEntityDetailHandler(deps);
 75→  const entityActionsHandler = createEntityActionsHandler(deps);
 76→  const workItemAcceptHandler = createWorkItemAcceptHandler(deps);
 77→  const branchConversationHandler = createBranchConversationHandler(deps);
 78→  const githubWebhookHandler = createGitHubWebhookHandler(deps);
