 4→export interface LocalProviderOptions {
 5→  host?: string;
 6→  port?: number;
 7→  token?: string;
 8→  binaryPath?: string;
 9→  log?: SandboxAgentSpawnLogMode;
10→  env?: Record<string, string>;
11→}
12→
13→const localSandboxes = new Map<string, SandboxAgentSpawnHandle>();
14→
15→type LocalSandboxProvider = SandboxProvider & {
16→  getToken(sandboxId: string): Promise<string | undefined>;
17→};
18→
19→export function local(options: LocalProviderOptions = {}): SandboxProvider {
20→  const provider: LocalSandboxProvider = {
21→    name: "local",
22→    async create(): Promise<string> {
23→      const handle = await spawnSandboxAgent(
24→        {
25→          host: options.host,
26→          port: options.port,
27→          token: options.token,
28→          binaryPath: options.binaryPath,
29→          log: options.log,
30→          env: options.env,
31→        } satisfies SandboxAgentSpawnOptions,
32→        globalThis.fetch?.bind(globalThis),
33→      );
34→
35→      const rawSandboxId = baseUrlToSandboxId(handle.baseUrl);
36→      localSandboxes.set(rawSandboxId, handle);
37→      return rawSandboxId;
38→    },
39→    async destroy(sandboxId: string): Promise<void> {
40→      const handle = localSandboxes.get(sandboxId);
41→      if (!handle) {
42→        return;
43→      }
44→      localSandboxes.delete(sandboxId);
45→      await handle.dispose();
46→    },
47→    async getUrl(sandboxId: string): Promise<string> {
48→      return `http://${sandboxId}`;
49→    },
50→    async getFetch(sandboxId: string): Promise<typeof globalThis.fetch> {
51→      const handle = localSandboxes.get(sandboxId);
52→      const token = options.token ?? handle?.token;
53→      const fetcher = globalThis.fetch?.bind(globalThis);
54→      if (!fetcher) {
55→        throw new Error("Fetch API is not available; provide a fetch implementation.");
56→      }
57→
58→      if (!token) {
59→        return fetcher;
60→      }
61→
62→      return async (input, init) => {
63→        const request = new Request(input, init);
64→        const targetUrl = new URL(request.url);
65→        targetUrl.protocol = "http:";
66→        targetUrl.host = sandboxId;
67→        const headers = new Headers(request.headers);
68→        if (!headers.has("authorization")) {
69→          headers.set("authorization", `Bearer ${token}`);
70→        }
71→        const forwarded = new Request(targetUrl.toString(), request);
72→        return fetcher(new Request(forwarded, { headers }));
73→      };
74→    },
75→    async getToken(sandboxId: string): Promise<string | undefined> {
76→      return options.token ?? localSandboxes.get(sandboxId)?.token;
77→    },
78→  };
79→  return provider;
80→}
