 40→export async function spawnSandboxAgent(options: SandboxAgentSpawnOptions, fetcher?: typeof fetch): Promise<SandboxAgentSpawnHandle> {
 41→  if (!isNodeRuntime()) {
 42→    throw new Error("Autospawn requires a Node.js runtime.");
 43→  }
 44→
 45→  const { spawn } = await import("node:child_process");
 46→  const crypto = await import("node:crypto");
 47→  const fs = await import("node:fs");
 48→  const path = await import("node:path");
 49→  const net = await import("node:net");
 50→  const { createRequire } = await import("node:module");
 51→
 52→  const bindHost = options.host ?? "127.0.0.1";
 53→  const port = options.port ?? (await getFreePort(net, bindHost));
 54→  const connectHost = bindHost === "0.0.0.0" || bindHost === "::" ? "127.0.0.1" : bindHost;
 55→  const token = options.token ?? crypto.randomBytes(24).toString("hex");
 56→  const timeoutMs = options.timeoutMs ?? 15_000;
 57→  const logMode: SandboxAgentSpawnLogMode = options.log ?? "inherit";
 58→
 59→  const binaryPath =
 60→    options.binaryPath ??
 61→    resolveBinaryFromEnv(fs, path) ??
 62→    resolveBinaryFromCliPackage(createRequire(import.meta.url), path, fs) ??
 63→    resolveBinaryFromPath(fs, path);
 64→
 65→  if (!binaryPath) {
 66→    throw new Error("sandbox-agent binary not found. Install @sandbox-agent/cli or set SANDBOX_AGENT_BIN.");
 67→  }
 68→
 69→  if (!assertExecutable(binaryPath, fs)) {
 70→    throw new Error(
 71→      formatNonExecutableBinaryMessage({
 72→        binPath: binaryPath,
 73→        trustPackages: TRUST_PACKAGES,
 74→        bunInstallBlocks: [
 75→          {
 76→            label: "Project install",
 77→            commands: [`bun pm trust ${TRUST_PACKAGES}`, "bun add sandbox-agent"],
 78→          },
 79→          {
 80→            label: "Global install",
 81→            commands: [`bun pm -g trust ${TRUST_PACKAGES}`, "bun add -g sandbox-agent"],
 82→          },
 83→        ],
 84→      }),
 85→    );
 86→  }
 87→
 88→  const stdio = logMode === "inherit" ? "inherit" : logMode === "silent" ? "ignore" : "pipe";
 89→  const args = ["server", "--host", bindHost, "--port", String(port), "--token", token];
 90→  const child = spawn(binaryPath, args, {
 91→    stdio,
 92→    env: {
 93→      ...process.env,
 94→      ...(options.env ?? {}),
 95→    },
 96→  });
 97→  const cleanup = registerProcessCleanup(child);
 98→
 99→  const baseUrl = `http://${connectHost}:${port}`;
100→  const ready = waitForHealth(baseUrl, fetcher ?? globalThis.fetch, timeoutMs, child, token);
101→
102→  await ready;
103→
104→  const dispose = async () => {
105→    if (child.exitCode !== null) {
106→      cleanup.dispose();
107→      return;
108→    }
109→    child.kill("SIGTERM");
110→    const exited = await waitForExit(child, 5_000);
111→    if (!exited) {
112→      child.kill("SIGKILL");
113→    }
114→    cleanup.dispose();
115→  };
116→
117→  return { baseUrl, token, child, dispose };
118→}
