120→function resolveBinaryFromEnv(fs: typeof import("node:fs"), path: typeof import("node:path")): string | null {
121→  const value = process.env.SANDBOX_AGENT_BIN;
122→  if (!value) {
123→    return null;
124→  }
125→  const resolved = path.resolve(value);
126→  if (fs.existsSync(resolved)) {
127→    return resolved;
128→  }
129→  return null;
130→}
131→
132→function resolveBinaryFromCliPackage(
133→  require: ReturnType<typeof import("node:module").createRequire>,
134→  path: typeof import("node:path"),
135→  fs: typeof import("node:fs"),
136→): string | null {
137→  const key = `${process.platform}-${process.arch}`;
138→  const pkg = PLATFORM_PACKAGES[key];
139→  if (!pkg) {
140→    return null;
141→  }
142→  try {
143→    const pkgPath = require.resolve(`${pkg}/package.json`);
144→    const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
145→    const resolved = path.join(path.dirname(pkgPath), "bin", bin);
146→    return fs.existsSync(resolved) ? resolved : null;
147→  } catch {
148→    return null;
149→  }
150→}
151→
152→function resolveBinaryFromPath(fs: typeof import("node:fs"), path: typeof import("node:path")): string | null {
153→  const pathEnv = process.env.PATH ?? "";
154→  const separator = process.platform === "win32" ? ";" : ":";
155→  const candidates = pathEnv.split(separator).filter(Boolean);
156→  const bin = process.platform === "win32" ? "sandbox-agent.exe" : "sandbox-agent";
157→  for (const dir of candidates) {
158→    const resolved = path.join(dir, bin);
159→    if (fs.existsSync(resolved)) {
160→      return resolved;
161→    }
162→  }
163→  return null;
164→}
