166→async function getFreePort(net: typeof import("node:net"), host: string): Promise<number> {
167→  return new Promise((resolve, reject) => {
168→    const server = net.createServer();
169→    server.unref();
170→    server.on("error", reject);
171→    server.listen(0, host, () => {
172→      const address = server.address() as AddressInfo;
173→      server.close(() => resolve(address.port));
174→    });
175→  });
176→}
