178→async function waitForHealth(baseUrl: string, fetcher: typeof fetch | undefined, timeoutMs: number, child: ChildProcess, token: string): Promise<void> {
179→  if (!fetcher) {
180→    throw new Error("Fetch API is not available; provide a fetch implementation.");
181→  }
182→  const start = Date.now();
183→  let lastError: string | undefined;
184→
185→  while (Date.now() - start < timeoutMs) {
186→    if (child.exitCode !== null) {
187→      throw new Error("sandbox-agent exited before becoming healthy.");
188→    }
189→    try {
190→      const response = await fetcher(`${baseUrl}/v1/health`, {
191→        headers: { Authorization: `Bearer ${token}` },
192→      });
193→      if (response.ok) {
194→        return;
195→      }
196→      lastError = `status ${response.status}`;
197→    } catch (err) {
198→      lastError = err instanceof Error ? err.message : String(err);
199→    }
200→    await new Promise((resolve) => setTimeout(resolve, 200));
201→  }
202→
203→  throw new Error(`Timed out waiting for sandbox-agent health (${lastError ?? "unknown error"}).`);
204→}
205→
206→async function waitForExit(child: ChildProcess, timeoutMs: number): Promise<boolean> {
207→  if (child.exitCode !== null) {
208→    return true;
209→  }
210→  return new Promise((resolve) => {
211→    const timer = setTimeout(() => resolve(false), timeoutMs);
212→    child.once("exit", () => {
213→      clearTimeout(timer);
214→      resolve(true);
215→    });
216→  });
217→}
218→
219→function registerProcessCleanup(child: ChildProcess): { dispose: () => void } {
220→  const handler = () => {
221→    if (child.exitCode === null) {
222→      child.kill("SIGTERM");
223→    }
224→  };
225→
226→  process.once("exit", handler);
227→  process.once("SIGINT", handler);
228→  process.once("SIGTERM", handler);
229→
230→  return {
231→    dispose: () => {
232→      process.off("exit", handler);
233→      process.off("SIGINT", handler);
234→      process.off("SIGTERM", handler);
235→    },
236→  };
237→}
