118→/**
119→ * Spawn a sandbox-agent instance for testing.
120→ * Each test should spawn its own instance on a unique port.
121→ */
122→export async function spawnSandboxAgent(options: SpawnOptions = {}): Promise<SandboxAgentHandle> {
123→  const binaryPath = findBinary();
124→  if (!binaryPath) {
125→    throw new Error("sandbox-agent binary not found. Run 'cargo build -p sandbox-agent' first or set SANDBOX_AGENT_BIN.");
126→  }
127→
128→  const host = options.host ?? "127.0.0.1";
129→  const port = options.port ?? (await getFreePort(host));
130→  const token = options.token ?? randomBytes(24).toString("hex");
131→  const timeoutMs = options.timeoutMs ?? 30_000;
132→
133→  const args = ["server", "--host", host, "--port", String(port), "--token", token];
134→  const tempStateDir = mkdtempSync(join(tmpdir(), "sandbox-agent-opencode-"));
135→  const sqlitePath = join(tempStateDir, "opencode-sessions.db");
136→
137→  const compatEnv = {
138→    OPENCODE_COMPAT_FIXED_TIME_MS: "1700000000000",
139→    OPENCODE_COMPAT_DIRECTORY: "/workspace",
140→    OPENCODE_COMPAT_WORKTREE: "/workspace",
141→    OPENCODE_COMPAT_HOME: "/home/opencode",
142→    OPENCODE_COMPAT_STATE: "/state/opencode",
143→    OPENCODE_COMPAT_CONFIG: "/config/opencode",
144→    OPENCODE_COMPAT_BRANCH: "main",
145→    OPENCODE_COMPAT_DB_PATH: sqlitePath,
146→  };
147→
148→  const child = spawn(binaryPath, args, {
149→    stdio: "pipe",
150→    env: {
151→      ...process.env,
152→      ...compatEnv,
153→      ...(options.env ?? {}),
154→    },
155→  });
156→
157→  // Collect stderr for debugging
158→  let stderr = "";
159→  const logFile = process.env.SANDBOX_AGENT_TEST_LOG_FILE;
160→  child.stderr?.on("data", (chunk) => {
161→    const text = chunk.toString();
162→    stderr += text;
163→    if (logFile) appendFileSync(logFile, `[stderr] ${text}`);
164→    if (process.env.SANDBOX_AGENT_TEST_LOGS) {
165→      process.stderr.write(text);
166→    }
167→  });
168→  child.stdout?.on("data", (chunk) => {
169→    if (logFile) appendFileSync(logFile, `[stdout] ${chunk.toString()}`);
170→    if (process.env.SANDBOX_AGENT_TEST_LOGS) {
171→      process.stderr.write(chunk.toString());
172→    }
173→  });
174→
175→  const baseUrl = `http://${host}:${port}`;
176→
177→  try {
178→    await waitForHealth(baseUrl, token, timeoutMs, child);
179→  } catch (err) {
180→    child.kill("SIGKILL");
181→    if (stderr) {
182→      throw new Error(`${err}. Stderr: ${stderr}`);
183→    }
184→    throw err;
185→  }
186→
187→  const dispose = async () => {
188→    if (child.exitCode !== null) {
189→      rmSync(tempStateDir, { recursive: true, force: true });
190→      return;
191→    }
192→    child.kill("SIGTERM");
193→    const exited = await waitForExit(child, 5_000);
194→    if (!exited) {
195→      child.kill("SIGKILL");
196→    }
197→    rmSync(tempStateDir, { recursive: true, force: true });
198→  };
199→
200→  return { baseUrl, token, child, dispose };
201→}
