313→    pub async fn run_once(&self, spec: RunSpec) -> Result<RunOutput, SandboxError> {
314→        if spec.command.trim().is_empty() {
315→            return Err(SandboxError::InvalidRequest {
316→                message: "command must not be empty".to_string(),
317→            });
318→        }
319→
320→        let config = self.get_config().await;
321→        let mut timeout_ms = spec.timeout_ms.unwrap_or(config.default_run_timeout_ms);
322→        if timeout_ms == 0 {
323→            timeout_ms = config.default_run_timeout_ms;
324→        }
325→        timeout_ms = timeout_ms.min(config.max_run_timeout_ms);
326→
327→        let max_output_bytes = spec
328→            .max_output_bytes
329→            .unwrap_or(config.max_output_bytes)
330→            .min(config.max_output_bytes);
331→
332→        let mut cmd = Command::new(&spec.command);
333→        cmd.args(&spec.args)
334→            .stdin(std::process::Stdio::null())
335→            .stdout(std::process::Stdio::piped())
336→            .stderr(std::process::Stdio::piped());
337→
338→        if let Some(cwd) = &spec.cwd {
339→            cmd.current_dir(cwd);
340→        }
341→
342→        if !spec.env.contains_key("TERM") {
343→            cmd.env("TERM", "xterm-256color");
344→        }
345→        for (key, value) in &spec.env {
346→            cmd.env(key, value);
347→        }
348→
349→        let mut child = cmd.spawn().map_err(|err| SandboxError::StreamError {
350→            message: format!("failed to spawn process: {err}"),
351→        })?;
352→
353→        let stdout = child
354→            .stdout
355→            .take()
356→            .ok_or_else(|| SandboxError::StreamError {
357→                message: "failed to capture stdout".to_string(),
358→            })?;
359→        let stderr = child
360→            .stderr
361→            .take()
362→            .ok_or_else(|| SandboxError::StreamError {
363→                message: "failed to capture stderr".to_string(),
364→            })?;
365→
366→        let started = Instant::now();
367→        let stdout_task = tokio::spawn(capture_output(stdout, max_output_bytes));
368→        let stderr_task = tokio::spawn(capture_output(stderr, max_output_bytes));
369→
370→        let wait_result =
371→            tokio::time::timeout(std::time::Duration::from_millis(timeout_ms), child.wait()).await;
372→
373→        let (exit_code, timed_out) = match wait_result {
374→            Ok(Ok(status)) => (status.code(), false),
375→            Ok(Err(err)) => {
376→                let _ = child.kill().await;
377→                return Err(SandboxError::StreamError {
378→                    message: format!("failed to wait on process: {err}"),
379→                });
380→            }
381→            Err(_) => {
382→                let _ = child.kill().await;
383→                let _ = child.wait().await;
384→                (None, true)
385→            }
386→        };
387→
388→        let (stdout, stdout_truncated) = match stdout_task.await {
389→            Ok(Ok(captured)) => captured,
390→            _ => (Vec::new(), false),
391→        };
392→        let (stderr, stderr_truncated) = match stderr_task.await {
393→            Ok(Ok(captured)) => captured,
394→            _ => (Vec::new(), false),
395→        };
396→
397→        Ok(RunOutput {
398→            exit_code,
399→            timed_out,
400→            stdout: String::from_utf8_lossy(&stdout).to_string(),
401→            stderr: String::from_utf8_lossy(&stderr).to_string(),
402→            stdout_truncated,
403→            stderr_truncated,
404→            duration_ms: started.elapsed().as_millis() as u64,
405→        })
406→    }
