408→    pub async fn list_processes(&self, owner: Option<ProcessOwner>) -> Vec<ProcessSnapshot> {
409→        let processes = self.inner.processes.read().await;
410→        let mut items = Vec::with_capacity(processes.len());
411→        for process in processes.values() {
412→            if owner.is_none_or(|expected| process.owner == expected) {
413→                items.push(process.snapshot().await);
414→            }
415→        }
416→        items.sort_by(|a, b| a.id.cmp(&b.id));
417→        items
418→    }
