599→    fn spawn_pipe_process(
600→        &self,
601→        spec: &ProcessStartSpec,
602→    ) -> Result<SpawnedPipeProcess, SandboxError> {
603→        let mut cmd = Command::new(&spec.command);
604→        cmd.args(&spec.args)
605→            .stdin(std::process::Stdio::piped())
606→            .stdout(std::process::Stdio::piped())
607→            .stderr(std::process::Stdio::piped());
608→
609→        if let Some(cwd) = &spec.cwd {
610→            cmd.current_dir(cwd);
611→        }
612→
613→        for (key, value) in &spec.env {
614→            cmd.env(key, value);
615→        }
616→
617→        let mut child = cmd.spawn().map_err(|err| SandboxError::StreamError {
618→            message: format!("failed to spawn process: {err}"),
619→        })?;
620→
621→        let stdin = child.stdin.take();
622→        let stdout = child
623→            .stdout
624→            .take()
625→            .ok_or_else(|| SandboxError::StreamError {
626→                message: "failed to capture stdout".to_string(),
627→            })?;
628→        let stderr = child
629→            .stderr
630→            .take()
631→            .ok_or_else(|| SandboxError::StreamError {
632→                message: "failed to capture stderr".to_string(),
633→            })?;
634→
635→        Ok(SpawnedPipeProcess {
636→            runtime: ManagedRuntime {
637→                pid: child.id(),
638→                stdin: stdin.map(ProcessStdin::Pipe),
639→                #[cfg(unix)]
640→                pty_resize_fd: None,
641→            },
642→            child,
643→            stdout,
644→            stderr,
645→        })
646→    }
647→
648→    #[cfg(unix)]
649→    fn spawn_tty_process(
650→        &self,
651→        spec: &ProcessStartSpec,
652→    ) -> Result<SpawnedTtyProcess, SandboxError> {
653→        use std::os::fd::AsRawFd;
654→        use std::process::Stdio;
655→
656→        let (master_fd, slave_fd) = open_pty(80, 24)?;
657→        let slave_raw = slave_fd.as_raw_fd();
658→
659→        let stdin_fd = dup_fd(slave_raw)?;
660→        let stdout_fd = dup_fd(slave_raw)?;
661→        let stderr_fd = dup_fd(slave_raw)?;
662→
663→        let mut cmd = Command::new(&spec.command);
664→        cmd.args(&spec.args)
665→            .stdin(Stdio::from(std::fs::File::from(stdin_fd)))
666→            .stdout(Stdio::from(std::fs::File::from(stdout_fd)))
667→            .stderr(Stdio::from(std::fs::File::from(stderr_fd)));
668→
669→        if let Some(cwd) = &spec.cwd {
670→            cmd.current_dir(cwd);
671→        }
672→
673→        for (key, value) in &spec.env {
674→            cmd.env(key, value);
675→        }
676→
677→        unsafe {
678→            cmd.pre_exec(move || {
679→                if libc::setsid() == -1 {
680→                    return Err(std::io::Error::last_os_error());
681→                }
682→                if libc::ioctl(slave_raw, libc::TIOCSCTTY as _, 0) == -1 {
683→                    return Err(std::io::Error::last_os_error());
684→                }
685→                Ok(())
686→            });
687→        }
688→
689→        let child = cmd.spawn().map_err(|err| SandboxError::StreamError {
690→            message: format!("failed to spawn tty process: {err}"),
691→        })?;
692→        let pid = child.id();
693→
694→        drop(slave_fd);
695→
696→        let master_raw = master_fd.as_raw_fd();
697→        let writer_fd = dup_fd(master_raw)?;
698→        let resize_fd = dup_fd(master_raw)?;
699→
700→        let reader_file = tokio::fs::File::from_std(std::fs::File::from(master_fd));
701→        let writer_file = tokio::fs::File::from_std(std::fs::File::from(writer_fd));
702→        let resize_file = std::fs::File::from(resize_fd);
703→
704→        Ok(SpawnedTtyProcess {
705→            runtime: ManagedRuntime {
706→                pid,
707→                stdin: Some(ProcessStdin::Pty(writer_file)),
708→                pty_resize_fd: Some(resize_file),
709→            },
710→            child,
711→            reader: reader_file,
712→        })
713→    }
714→}
