18→async function resolveValue<T>(value: T | (() => T | Promise<T>) | undefined, fallback: T): Promise<T> {
19→  if (value === undefined) {
20→    return fallback;
21→  }
22→  if (typeof value === "function") {
23→    return await (value as () => T | Promise<T>)();
24→  }
25→  return value;
26→}
