28→function extractMappedPort(
29→  inspect: { NetworkSettings?: { Ports?: Record<string, Array<{ HostPort?: string }> | null | undefined> } },
30→  containerPort: number,
31→): number {
32→  const hostPort = inspect.NetworkSettings?.Ports?.[`${containerPort}/tcp`]?.[0]?.HostPort;
33→  if (!hostPort) {
34→    throw new Error(`docker sandbox-agent port ${containerPort} is not published`);
35→  }
36→  return Number(hostPort);
37→}
