39→export function docker(options: DockerProviderOptions = {}): SandboxProvider {
40→  const image = options.image ?? DEFAULT_SANDBOX_AGENT_IMAGE;
41→  const host = options.host ?? DEFAULT_HOST;
42→  const agentPort = options.agentPort ?? DEFAULT_AGENT_PORT;
43→  const client = new Docker({ socketPath: "/var/run/docker.sock" });
44→
45→  return {
46→    name: "docker",
47→    defaultCwd: "/home/sandbox",
48→    async create(): Promise<string> {
49→      const hostPort = await getPort();
50→      const env = await resolveValue(options.env, []);
51→      const binds = await resolveValue(options.binds, []);
52→
53→      const container = await client.createContainer({
54→        Image: image,
55→        Cmd: ["server", "--no-token", "--host", "0.0.0.0", "--port", String(agentPort)],
56→        Env: env,
57→        ExposedPorts: { [`${agentPort}/tcp`]: {} },
58→        HostConfig: {
59→          AutoRemove: true,
60→          Binds: binds,
61→          PortBindings: {
62→            [`${agentPort}/tcp`]: [{ HostPort: String(hostPort) }],
63→          },
64→        },
65→        ...(options.createContainerOptions ?? {}),
66→      });
67→
68→      await container.start();
69→      return container.id;
70→    },
71→    async destroy(sandboxId: string): Promise<void> {
72→      const container = client.getContainer(sandboxId);
73→      try {
74→        await container.stop({ t: 5 });
75→      } catch {}
76→      try {
77→        await container.remove({ force: true });
78→      } catch {}
79→    },
80→    async getUrl(sandboxId: string): Promise<string> {
81→      const container = client.getContainer(sandboxId);
82→      const hostPort = extractMappedPort(await container.inspect(), agentPort);
83→      return `http://${host}:${hostPort}`;
84→    },
85→  };
